     1→import { useFocusEffect } from '@react-navigation/native';
     2→import React, { useCallback, useRef, useState } from 'react';
     3→import { WebViewProps } from 'react-native-webview';
     4→import AnimationArrows from '../../atomic/atoms/AnimationArrows';
     5→import ApiError from '../../atomic/organisms/ApiError';
     6→import BasicScreen from '../../atomic/templates/BasicScreen';
     7→import { useScreenViewTracking } from '../../hooks/tracking';
     8→import { useMarketplace } from '../../services';
     9→import { PARAMS_GET_MARKETPLACE } from './data';
    10→import { RewardProgramMarketplaceWebProps } from './Models';
    11→import View from './view';
    12→
    13→const RewardProgramMarketplaceWebView = ({
    14→  navigation,
    15→  route,
    16→}: RewardProgramMarketplaceWebProps) => {
    17→  useScreenViewTracking({
    18→    route,
    19→    title: 'Shopping',
    20→  });
    21→
    22→  const { data, isLoading, isError, requestGetMarketplace } = useMarketplace();
    23→
    24→  const [isLocalError, setIsLocalError] = useState(false);
    25→  const webViewRef = useRef<WebViewProps>(null);
    26→
    27→  const requestGetMarketplaceCallback = useCallback(() => {
    28→    requestGetMarketplace(PARAMS_GET_MARKETPLACE);
    29→  }, [requestGetMarketplace]);
    30→
    31→  useFocusEffect(requestGetMarketplaceCallback);
    32→
    33→  const handleGoBack = () => {
    34→    navigation.goBack();
    35→  };
    36→
    37→  const handleError = () => {
    38→    setIsLocalError(true);
    39→  };
    40→
    41→  if (isLoading) {
    42→    return <AnimationArrows />;
    43→  }
    44→
    45→  if (isError || !data || isLocalError) {
    46→    return (
    47→      <BasicScreen
    48→        leftIconOnPress={handleGoBack}
    49→        title="Shopping"
    50→        errorButtonOnPress={requestGetMarketplaceCallback}
    51→      >
    52→        <ApiError onPress={requestGetMarketplaceCallback} />
    53→      </BasicScreen>
    54→    );
    55→  }
    56→
    57→  return (
    58→    <View
    59→      webViewRef={webViewRef}
    60→      uri={data.dados.redirectURL}
    61→      onBackPress={handleGoBack}
    62→      errorButtonOnPress={handleError}
    63→      onError={handleError}
    64→    />
    65→  );
    66→};
    67→
    68→export default RewardProgramMarketplaceWebView;
    69→

