     3→import React, {
     4→  FC,
     5→  useCallback,
     6→  useEffect,
     7→  useMemo,
     8→  useRef,
     9→  useState,
    10→} from 'react';
    11→import {
    12→  eventModalView,
    13→  eventScreenViewV3,
    14→  eventSelectContent,
    15→} from '~/constants/functions';
    16→import ApiError from '../../atomic/organisms/ApiError';
    17→import BasicScreen from '../../atomic/templates/BasicScreen';
    18→import { useCardBuilderWhereUseMyPoints } from '../../hooks/custom/useCardBuilderWhereUseMyPoints';
    19→import { getParameterPointsProgram, usePoints } from '../../services';
    20→import { PointsProps } from './Models';
    21→import PointsView from './view';
    22→
    23→const Points: FC<PointsProps> = ({ navigation }) => {
    24→  const {
    25→    points,
    26→    products,
    27→    isLoadingBalance,
    28→    isErrorBalance,
    29→    isErrorProducts,
    30→    requestInitialData,
    31→    requestPointsBalance,
    32→    requestPointsProducts,
    33→    clear,
    34→    clearBalance,
    35→  } = usePoints();
    36→  const hasFocused = useRef(false);
    37→  const modalizeRef = useRef<PropsModalizeRef>(
    38→    null as unknown as PropsModalizeRef,
    39→  );
    40→  const [isMyOrders, setIsMyOrders] = useState(false);
    41→
    42→  const handleMyOrders = useCallback(() => {
    43→    navigation.navigate('MyOrdersRewardProgram');
    44→  }, [navigation]);
    45→
    46→  const handleGoBack = useCallback(() => {
    47→    navigation.goBack();
    48→  }, [navigation]);
    49→
    50→  const handlerGoHome = useCallback(() => {
    51→    navigation.navigate('Home' as never);
    52→  }, [navigation]);
    53→
    54→  const handleOpenDefault = () => {
    55→    eventSelectContent({
    56→      content_type: 'cta',
    57→      content_id: 'informacao_pontos',
    58→      location_1: 'monetizacao',
    59→      location_2: 'hub_recompensas_spmais',
    60→      location_3: 'home_hub_recompensas',
    61→    });
    62→
    63→    modalizeRef.current?.open?.();
    64→  };
    65→
    66→  const handleOpenMyOrders = () => {
    67→    setIsMyOrders(true);
    68→
    69→    eventModalView({
    70→      content_id: 'menu_header',
    71→      location_1: 'monetizacao',
    72→      location_2: 'hub_recompensas_spmais',
    73→      location_3: 'home_hub_recompensas',
    74→    });
    75→  };
    76→
    77→  const buildPointsCardItems = useCardBuilderWhereUseMyPoints();
    78→
    79→  const requestPointsCallback = useCallback(() => {
    80→    requestPointsBalance();
    81→    requestPointsProducts();
    82→    getParameterPointsProgram();
    83→  }, [
    84→    requestPointsBalance,
    85→    requestPointsProducts,
    86→  ]);
    87→
    88→  const handleApiErrorPress = useCallback(() => {
    89→    if (isErrorBalance || isErrorProducts) {
    90→      requestPointsCallback();
    91→    }
    92→  }, [
    93→    isErrorBalance,
    94→    isErrorProducts,
    95→    requestPointsCallback,
    96→  ]);
    97→
    98→  useFocusEffect(
    99→    useCallback(() => {
   100→      if (!hasFocused.current) {
   101→        eventScreenViewV3(
   102→          'home_hub_recompensas',
   103→          'hub_recompensas_spmais',
   104→          'monetizacao',
   105→          {
   106→            location_1: 'monetizacao',
   107→            location_2: 'hub_recompensas_spmais',
   108→            location_3: 'home_hub_recompensas',
   109→          },
   110→        );
   111→        hasFocused.current = true;
   112→        clearBalance();
   113→      }
   114→      return () => {
   115→        hasFocused.current = false;
   116→      };
   117→    }, [clearBalance]),
   118→  );
   119→
   120→  useEffect(() => {
   121→    requestInitialData();
   122→
   123→    return () => {
   124→      clear();
   125→    };
   126→  }, [
   127→    requestInitialData,
   128→    clear,
   129→  ]);
   130→
   131→  useFocusEffect(
   132→    useCallback(() => {
   133→      requestPointsCallback();
   134→      return undefined;
   135→    }, [requestPointsCallback]),
   136→  );
   137→
   138→  const view = useMemo(() => {
   139→    if (isErrorProducts || isErrorBalance) {
