    37→  const [hasAttemptedRescue, setHasAttemptedRescue] = useState(false);
    38→
    39→  const { conversionFactor } = usePoints();
    40→  const {
    41→    isLoading: isRescueLoading,
    42→    isError: isRescueFailed,
    43→    responseStatus: rescueStatus,
    44→    rescueRequest,
    45→    reset: rescueClear,
