   152→    if (
   153→      showResult &&
   154→      isRescueConcluded &&
   155→      !alreadyMarkedRef.current &&
   156→      hasRedeemed !== true
   157→    ) {
   158→      alreadyMarkedRef.current = true;
   159→      markAsRedeemed().catch(() => {});
   160→    }
   161→  }, [
   162→    showResult,
   163→    isRescueConcluded,
   164→    hasRedeemed,
   165→    markAsRedeemed,
   166→  ]);
   167→
   168→  const nfPtBR = useMemo(() => new Intl.NumberFormat('pt-BR'), []);
   169→  const getFormatPoints = React.useCallback(
   170→    (n: number) => nfPtBR.format(Math.max(0, Math.floor(n || 0))),
   171→    [nfPtBR],
   172→  );
   173→  const formatCurrencyBR = (n: number) =>
   174→    new Intl.NumberFormat('pt-BR', {
   175→      style: 'currency',
   176→      currency: 'BRL',
   177→    })
   178→      .format(Number.isFinite(n) ? n : 0)
   179→      .replace(/\s/g, '');
   180→
   181→  const formattedSelectedPoints = useMemo(
