     1→import { PointsTransaction, TransactionType } from './Models';
     2→
     3→type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     4→type TagSubType =
     5→  | 'DRIVE_THRU'
     6→  | 'PEDAGIO'
     7→  | 'ESTACIONAMENTO'
     8→  | 'ABASTECIMENTO'
     9→  | 'LAVA_RAPIDO';
    10→
    11→interface TransactionDetailField {
    12→  label?: string;
    13→  value?: string;
    14→}
    15→
    16→export const getTransactionGainType = (
    17→  transaction: PointsTransaction,
    18→): TransactionGainType => {
    19→  const provider = transaction.details?.provider?.toLowerCase() || '';
    20→
    21→  if (provider.includes('cashback')) {
    22→    return 'CASHBACK';
    23→  }
    24→
    25→  const icon = transaction.icon?.toLowerCase() || '';
    26→  const description = transaction.description?.toLowerCase() || '';
    27→
    28→  const tagIndicators = [
    29→    'tag',
    30→    'pedágio',
    31→    'pedagio',
    32→    'estacionamento',
    33→    'abastecimento',
    34→    'abastece',
    35→    'drive',
    36→    'lava',
    37→    'rápido',
    38→  ];
    39→
    40→  const isTag = tagIndicators.some(
    41→    indicator =>
    42→      icon.includes(indicator) ||
    43→      description.includes(indicator) ||
    44→      provider.includes(indicator),
    45→  );
    46→
    47→  return isTag ? 'TAG' : 'CARD';
    48→};
    49→
    50→export const getTagSubType = (
    51→  transaction: PointsTransaction,
    52→): TagSubType | null => {
    53→  const description = transaction.description?.toUpperCase() || '';
    54→  const provider = transaction.details?.provider?.toUpperCase() || '';
    55→  const extraInfo = transaction.details?.extraInfo?.toUpperCase() || '';
    56→  const searchText = `${description} ${provider} ${extraInfo}`;
    57→
    58→  if (
    59→    searchText.includes('DRIVE') ||
    60→    searchText.includes('DRIVE-THRU') ||
    61→    searchText.includes('DRIVE THRU')
    62→  ) {
    63→    return 'DRIVE_THRU';
    64→  }
    65→  if (searchText.includes('PEDÁGIO') || searchText.includes('PEDAGIO')) {
    66→    return 'PEDAGIO';
    67→  }
    68→  if (searchText.includes('ESTACIONAMENTO')) {
    69→    return 'ESTACIONAMENTO';
    70→  }
    71→  if (searchText.includes('ABASTECIMENTO') || searchText.includes('ABASTECE')) {
    72→    return 'ABASTECIMENTO';
    73→  }
    74→  if (searchText.includes('LAVA') && searchText.includes('RÁPIDO')) {
    75→    return 'LAVA_RAPIDO';
    76→  }
    77→
    78→  return null;
    79→};
    80→
    81→export const getDetailScreenTitle = (
    82→  gainType: TransactionGainType,
    83→  transactionType?: TransactionType,
    84→): string => {
    85→  if (gainType === 'CASHBACK' && transactionType === 'RESCUE') {
    86→    return 'Detalhes de uso';
    87→  }
    88→  if (gainType === 'CASHBACK') {
    89→    return 'Detalhes do Cashback';
    90→  }
    91→  return gainType === 'CARD' ? 'Detalhes da compra' : 'Detalhes da pontuação';
    92→};
    93→
    94→export const getVehicleInfo = (
    95→  transaction: PointsTransaction,
    96→): string | null => {
    97→  const fields: TransactionDetailField[] = transaction.details?.fields || [];
    98→
    99→  const marcaField = fields.find((f: TransactionDetailField) =>
   100→    f.label?.toLowerCase().includes('marca'));
   101→  const modeloField = fields.find((f: TransactionDetailField) =>
   102→    f.label?.toLowerCase().includes('modelo'));
   103→  const placaField = fields.find((f: TransactionDetailField) =>
   104→    f.label?.toLowerCase().includes('placa'));
   105→
   106→  const marca = marcaField?.value || '';
   107→  const modelo = modeloField?.value || '';
   108→  const placa = placaField?.value || '';
   109→
   110→  if (marca && modelo && placa) {
   111→    return `${marca} ${modelo} - ${placa}`;
   112→  }
   113→
   114→  if (placa) {
   115→    return placa;
   116→  }
   117→
   118→  const origemField = fields.find(
   119→    (f: TransactionDetailField) =>
   120→      f.label?.toLowerCase().includes('origem') ||
   121→      f.label?.toLowerCase().includes('origin'),
   122→  );
   123→
   124→  if (origemField?.value) {
   125→    return origemField.value;
   126→  }
   127→
   128→  return null;
   129→};
   130→
   131→export const getPurchaseTypeLabel = (tagSubType: TagSubType | null): string => {
   132→  if (!tagSubType) return '';
   133→
   134→  const labels: Record<TagSubType, string> = {
   135→    DRIVE_THRU: 'Drive Thru',
   136→    PEDAGIO: 'Pedágio',
   137→    ESTACIONAMENTO: 'Estacionamento',
   138→    ABASTECIMENTO: 'Abastecimento',
   139→    LAVA_RAPIDO: 'Lava Rápido',
   140→  };
   141→
   142→  return labels[tagSubType] || '';
   143→};
   144→
   145→export const getOrigin = (transaction: PointsTransaction): string | null => {
   146→  const fields: TransactionDetailField[] = transaction.details?.fields || [];
   147→
   148→  const origemField = fields.find(
   149→    (f: TransactionDetailField) =>
   150→      f.label?.toLowerCase().includes('origem') ||
   151→      f.label?.toLowerCase().includes('origin'),
   152→  );
   153→
   154→  return origemField?.value || null;
   155→};
   156→
   157→export const getFormattedPointsValue = (
   158→  amount: number,
   159→  type: TransactionType,
   160→): string => {
   161→  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
   162→  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
   163→  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
   164→};
   165→
   166→export const getFormattedHighlightText = (
   167→  date: string,
   168→  gainType: TransactionGainType,
   169→  moment: any,
   170→): string => {
   171→  const transactionDate = moment(date);
   172→  const day = transactionDate.format('DD');
   173→  const month = transactionDate.format('MMM').toLowerCase();
   174→  const year = transactionDate.format('YYYY');
   175→  const time = transactionDate.format('HH:mm');
   176→
   177→  if (gainType === 'CASHBACK') {
   178→    return `Pontos usados em ${day} ${month} ${year} às ${time}`;
   179→  }
   180→
   181→  return `Compra feita em ${day} ${month} ${year} às ${time}`;
   182→};
