     3→export const normalizeName = (value: unknown): string => {
     4→  if (typeof value === 'string') {
     5→    return value
     6→      .trim()
     7→      .toLowerCase()
     8→      .normalize('NFD')
     9→      .replace(/[\u0300-\u036f]/g, '');
    10→  }
    11→
    12→  if (value === null || value === undefined) {
    13→    return '';
    14→  }
    15→
    16→  if (typeof value === 'number' || typeof value === 'boolean') {
    17→    return String(value)
    18→      .trim()
    19→      .toLowerCase()
    20→      .normalize('NFD')
    21→      .replace(/[\u0300-\u036f]/g, '');
    22→  }
    23→
    24→  return '';
    25→};
    26→
    27→export const extractRawProducts = (
    28→  pointsOptions: PointsProduct[] | undefined,
    29→): PointsProduct[] => {
    30→  if (!Array.isArray(pointsOptions)) {
    31→    return [];
    32→  }
    33→  return Array.isArray(pointsOptions[1]) ? pointsOptions[1] : pointsOptions;
    34→};
    35→
    36→export const isValidProduct = (product: unknown): product is PointsProduct => {
    37→  return (
    38→    product !== null &&
    39→    typeof product === 'object' &&
    40→    'name' in product &&
    41→    typeof (product as PointsProduct).name === 'string'
    42→  );
    43→};
